   {
    "name": "InvalidRequestException",
    "description": "The 'keyword' parameter is empty."
   }
  ]
 },
 {
  "name": "GmailSendEmail",
  "summary": "Send an email to one or multiple recipients, with optional scheduling, cc, and bcc.",
